import { BaseRadioGroup } from './BaseRadioGroup';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';
import {
  FieldWrapper,
  FieldWrapperProps,
} from '@/components/molecules/FieldWrapper/FieldWrapper';

export type RadioGroupProps = ComponentPropsWithoutRef<typeof BaseRadioGroup> &
  WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function RadioGroup({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'sm',
  labelPosition = 'left',
  children,
  ...props
}: RadioGroupProps) {
  return (
    <FieldWrapper
      isRequired={isRequired}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
      tooltip={tooltip}
      description={description}
      id={id}
      alignLabel="top"
    >
      <BaseRadioGroup {...props}>{children}</BaseRadioGroup>
    </FieldWrapper>
  );
}
